class Solution:
    def latestTimeCatchTheBus(self, buses, passengers, capacity):
        bs = sorted(buses)
        ps = sorted(passengers)
        pset = set(ps)
        # brute: try every candidate time from high to low (bounded by max bus time)
        # determine for a given arrival y whether you can board.
        def can_board(y):
            if y in pset:
                return False
            arrivals = sorted(ps + [y])
            j = 0
            for b in bs:
                seats = capacity
                while j < len(arrivals) and seats > 0 and arrivals[j] <= b:
                    if arrivals[j] == y:
                        return True
                    j += 1
                    seats -= 1
            return False
        hi = max(bs)
        for y in range(hi, -1, -1):
            if can_board(y):
                return y
        return -1

