var latestTimeCatchTheBus = function(buses, passengers, capacity) {
    buses.sort((a, b) => a - b);
    passengers.sort((a, b) => a - b);
    const pset = new Set(passengers);
    let j = 0;
    let cand = 0;
    for (let idx = 0; idx < buses.length; idx++) {
        const b = buses[idx];
        let seats = capacity;
        const taken = [];
        while (j < passengers.length && seats > 0 && passengers[j] <= b) {
            taken.push(passengers[j]);
            j++;
            seats--;
        }
        if (idx === buses.length - 1) {
            cand = seats > 0 ? b : taken[taken.length - 1];
        }
    }
    let y = cand;
    while (pset.has(y)) y--;
    return y;
};
